Actionscript.script:
stop();
var targetFrame = _parent._parent._parent.牙狼剑帧;
if (targetFrame != undefined) {
    gotoAndStop(targetFrame);
}

onClipEvent(enterFrame){
   if(_parent._parent._parent._parent._parent.状态 == "兵器攻击")
   {
      if (_parent._currentframe != 11 && random(10) == 0)
      {
         var myPoint = {x:this._x,y:this._y};
